var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"녀석의 존재가 세계침식률을 가속시킬 가능성은 얼마나 되지?","JPN":"やつの存在が世界侵食率を加速させる可能性はどれくらいだ？","ENG":"How likely is it that its presence will accelerate the Global Corruption rate?","TWN":"那傢伙的存在，加速世界侵蝕的可能性有多大？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 아직도 양자 위상차에 의한 이변이 일어나지 않는 걸 보면 특별히 문제는 없어 보이는군.","JPN":"そうだな。まだ量子位相差による異変が起きていないことからして、これと言った問題はなさそうだ。","ENG":"Hard to say. But since there's been no disturbance caused by quantum phase difference, I'd say we're in the clear for now.","TWN":"嗯，從目前看來，量子衛星引起的變異還沒有發生，所以應該沒有特別的問題。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…놈에게 문제가 생기면 바로 불러라.","JPN":"……やつに問題が生じたらすぐに呼べ。","ENG":"…If something goes wrong, call me immediately.","TWN":"…如果他有問題，馬上叫我。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몸 상태는 어떤가?","JPN":"体の調子はどうかね？","ENG":"How's your condition?","TWN":"你的身體狀況如何？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"허수공간에서 8년을 보냈다면 후유증이 남을 법도 한데 말이야.","JPN":"8年もの時間を虚数空間で過ごすと、後遺症が残ってもおかしくはないのだが。","ENG":"Spending eight years in the imaginary space, I'd expect some lasting side effects.","TWN":"在虛數空間待了8年，應該會留下後遺症才對。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 육신은 멀쩡하오. 부끄럽게도 말이지.","JPN":"恥ずかしながら某の肉体はなんともない。","ENG":"My body's intact. Shamefully so, in fact.","TWN":"我的身體沒事。說起來有點丟臉。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내겐 우물에서 있었던 일들이 방금 전처럼 생생하여… 설명을 듣기 전까진 그렇게 많은 시간이 흐른 줄도 몰랐소.","JPN":"某にとっては井戸での出来事がつい先程のように鮮明で……説明を聞くまでは、そこまで長い時間が過ぎていたとは気づかなかった。","ENG":"Everything that happened in the Well still feels as vivid as moments ago… I didn't realize how much time had passed until you told me.","TWN":"井裡發生的事，對我來說就像剛才一樣鮮明… 在聽你解釋之前，我根本不知道過了這麼久。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해하네. 8년이란 시간은 이 세계가 허수공간을 표류하던 자네의 존재를 배제한 채 흘려보낸 것이니까.","JPN":"なるほど。その8年は、虚数空間を漂流していた君の存在が排除されたまま、この世界が経験したもの。","ENG":"I understand. For this world, those eight years passed without you, while you drifted in imaginary space.","TWN":"我能理解。8年的時間，是這個世界在排除了你在虛數空間漂流的存在後流逝的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"엄밀히 따지면, 자네가 속한 시간은 1초도 뒤바뀌지 않은 셈이지.","JPN":"厳密にいうと、君が属した時間は1秒も変わっていないということだ。","ENG":"But your own timeline, strictly speaking, hasn't skipped a second.","TWN":"嚴格來說，你所屬的時間並沒有改變一秒。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"관리자님, 말씀하신 먹구름 발생 주기를 분석해봤습니다만…","JPN":"最高管理者、言われた通り墨雲の発生周期を分析しましたが……","ENG":"Administrator, I ran the analysis on the dark cloud frequency you mentioned–","TWN":"管理者，我分析了你所說的墨雲發生週期…"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"아, 실례했습니다. 다른 분과 대화 중이신 줄 몰랐네요.","JPN":"あ、失礼いたしました。他の方とのお話中だとは知らず……","ENG":"Ah, I'm sorry. I didn't realize you were speaking with someone.","TWN":"啊，不好意思。我不知道你正在和別人說話。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮네.","JPN":"大丈夫だ。","ENG":"It's fine.","TWN":"沒關係。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 분석 결과는 어떻지?","JPN":"それで、分析結果は？","ENG":"So, what did you find?","TWN":"那麼，分析結果如何？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"범이 힘의 갈무리를 거의 끝낸 것 같습니다. 이 진행속도라면 정확히 15일 뒤가 한계점이 될 겁니다.","JPN":"虎は力の収束をほぼ終えているようです。この進み具合なら、ちょうど15日後が限界点となるでしょう。","ENG":"The Tiger is nearly finished consolidating its strength. At this rate, the tipping point will hit in exactly fifteen days.","TWN":"老虎似乎已經快要完成力量的收納了。按照這個進度，極限點將在15天後到來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…동월?","JPN":"……トウゲツ？","ENG":"…Dongwol?","TWN":"…佟月？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"자네! 살아있었군!","JPN":"そなた、生きておったか！","ENG":"You're alive!","TWN":"你！你還活著！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"누구시죠? 제 이름은 어떻게…","JPN":"どちら様ですか？　どうしてボクの名前を……","ENG":"Um, do I know you? How do you know my name…?","TWN":"你是誰？你怎麼知道我的名字…"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국에서 근무하던 옛 요원일세. 우릴 돕기 위해 지금 막 관리국에 복귀했지.","JPN":"管理局に勤めていた昔の要員だ。我々に協力するために管理局に復帰したばかりでな。","ENG":"He's a former agent. Just rejoined the Administration to help us.","TWN":"我是曾在管理局工作過的前特工。為了幫助我們，我剛回到管理局。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"근황을 얘기하다 자네가 관리국에 얼마나 큰 도움이 되고 있는지 얘기하고 있었어.","JPN":"近況を伝え、君がいかに管理局にとって力になってくれているか、話していたのだよ。","ENG":"We were just talking about you, actually. About how much help you've been.","TWN":"我正在聊你的近況，說你在管理局給了我們多大的幫助。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"…그렇습니까? 좀 쑥스럽네요.","JPN":"……そうですか。少し恥ずかしいですね。","ENG":"…Really? I'm feeling shy.","TWN":"…是嗎？真有點不好意思。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관측을 계속해주게. 이상 상황이 발생하면 지금처럼 내게 바로 보고해주고.","JPN":"観測を続けてくれ。異常事態が発生したら、こうしてすぐに私に報告するように。","ENG":"Keep observing. Report to me immediately if anything unusual happens.","TWN":"繼續觀察。如果發生異常狀況，就像剛才一樣馬上向我報告。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"알겠습니다.","JPN":"かしこまりました。","ENG":"Understood.","TWN":"明白了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Hey.","TWN":"那個。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"돌아와 주셔서 감사합니다.","JPN":"帰ってきてくださってありがとうございます。","ENG":"Thank you for coming back.","TWN":"謝謝你回來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"지금 관리국은 한 사람의 도움이 정말 절실한 상황이거든요.","JPN":"今の管理局は、一人一人の助けが切実なんです。","ENG":"The Administration really needs all the help it can get right now.","TWN":"現在的管理局，真的非常需要一個人的幫助。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};